import React, { useEffect, useRef, useState } from "react";
import { Client } from "@stomp/stompjs";
import { Button } from "antd";
import "antd/dist/reset.css";
import "./App.css";

function App() {

  const [roomId, setRoomId] = useState("");
  const [joined, setJoined] = useState(false);
  const [participants, setParticipants] = useState(0);
  const [status, setStatus] = useState("idle");
  const [muted, setMuted] = useState(false);
  const [videoOff, setVideoOff] = useState(false);
  const socketRef = useRef(null);
  const iceQueue = useRef([]);

  const localVideo = useRef(null);
  const remoteVideo = useRef(null);

  const peerRef = useRef(null);


  const userId = useRef(
    Math.random().toString(36).substring(2)
  );

  const createRoom = () => {

    const id =
      Math.random()
        .toString(36)
        .substring(2, 8);

    setRoomId(id);
    setJoined(true);
  };

  const joinRoom = () => {

    if (!roomId.trim()) return;

    setJoined(true);
  };

  useEffect(() => {

    if (!joined) return;

    let peer;

    const start = async () => {

      try {

        setStatus("connecting");

        const stream =
          await navigator.mediaDevices.getUserMedia({
            video: true,
            audio: true,
          });

        localVideo.current.srcObject = stream;

        peer = new RTCPeerConnection({

          iceServers: [
            {
              urls: [
                "stun:stun.l.google.com:19302",
                "stun:global.stun.twilio.com:3478"
              ]
            }
          ],
        });

        peerRef.current = peer;

        stream.getTracks().forEach((track) => {
          peer.addTrack(track, stream);
        });

        peer.ontrack = (e) => {

          remoteVideo.current.srcObject =
            e.streams[0];
        };

        peer.onicecandidate = ({ candidate }) => {

          if (
            candidate &&
            socketRef.current?.connected
          ) {

            socketRef.current.publish({

              destination:
                `/app/ice/${roomId}`,

              body: JSON.stringify({
                candidate,
                sender: userId.current,
              }),
            });
          }
        };

        peer.onconnectionstatechange = () => {

          if (
            peer.connectionState ===
            "connected"
          ) {

            setStatus("connected");
          }

          if (
            peer.connectionState ===
            "failed" ||
            peer.connectionState ===
            "disconnected"
          ) {

            setStatus("disconnected");
          }
        };

        connectSocket(peer);

      } catch (e) {

        console.log(e);
      }
    };

    start();

    return () => {

      peer?.close();

      socketRef.current?.deactivate();

      const stream =
        localVideo.current?.srcObject;

      stream?.getTracks().forEach(
        (track) => track.stop()
      );
    };

  }, [joined]);

  const connectSocket = (peer) => {

    const client = new Client({

      brokerURL:
        window.location.protocol ===
          "https:"
          ? `wss://${window.location.host}/signal`
          : `ws://${window.location.hostname}:8081/signal`,

      reconnectDelay: 5000,

      onConnect: () => {

        client.publish({

          destination: "/app/join",

          body: JSON.stringify({
            roomId,
            userId: userId.current,
          }),
        });

        client.subscribe(
          `/topic/participants/${roomId}`,
          (msg) => {

            const users =
              JSON.parse(msg.body);

            setParticipants(users.length);
          }
        );

        client.subscribe(
          `/topic/offer/${roomId}`,
          async (msg) => {

            const data =
              JSON.parse(msg.body);

            if (
              data.sender ===
              userId.current
            )
              return;
            await peer.setRemoteDescription(
              data.sdp
            );

            for (const c of iceQueue.current) {

              await peer.addIceCandidate(c);
            }

            iceQueue.current = [];

            const answer =
              await peer.createAnswer();

            await peer.setLocalDescription(
              answer
            );

            client.publish({

              destination:
                `/app/answer/${roomId}`,

              body: JSON.stringify({
                sdp: answer,
                sender: userId.current,
              }),
            });
          }
        );

        client.subscribe(
          `/topic/answer/${roomId}`,
          async (msg) => {

            const data =
              JSON.parse(msg.body);

            if (
              data.sender ===
              userId.current
            )
              return;

            await peer.setRemoteDescription(
              data.sdp
            );
          }
        );
        client.subscribe(
          `/topic/ice/${roomId}`,
          async (msg) => {

            const data =
              JSON.parse(msg.body);

            if (
              data.sender ===
              userId.current
            )
              return;

            try {

              if (peer.remoteDescription) {

                await peer.addIceCandidate(
                  data.candidate
                );

              } else {

                iceQueue.current.push(
                  data.candidate
                );
              }

            } catch (e) {

              console.log(e);
            }
          }
        );

      },
    });

    client.activate();

    socketRef.current = client;
  };

  const startMeeting = async () => {

    const peer = peerRef.current;

    if (
      !peer ||
      !socketRef.current?.connected
    )
      return;

    const offer =
      await peer.createOffer();

    await peer.setLocalDescription(
      offer
    );

    socketRef.current.publish({

      destination:
        `/app/offer/${roomId}`,

      body: JSON.stringify({
        sdp: offer,
        sender: userId.current,
      }),
    });
  };

  const toggleMute = () => {

    const stream =
      localVideo.current?.srcObject;

    stream.getAudioTracks().forEach(
      (track) => {

        track.enabled =
          !track.enabled;

        setMuted(!track.enabled);
      }
    );
  };

  const toggleVideo = () => {

    const stream =
      localVideo.current?.srcObject;

    stream.getVideoTracks().forEach(
      (track) => {

        track.enabled =
          !track.enabled;

        setVideoOff(!track.enabled);
      }
    );
  };

  const leaveMeeting = () => {

    socketRef.current?.publish({

      destination: "/app/leave",

      body: JSON.stringify({
        roomId,
        userId: userId.current,
      }),
    });

    peerRef.current?.close();

    socketRef.current?.deactivate();

    const stream =
      localVideo.current?.srcObject;

    stream?.getTracks().forEach(
      (track) => track.stop()
    );

    if (localVideo.current) {
      localVideo.current.srcObject =
        null;
    }

    if (remoteVideo.current) {
      remoteVideo.current.srcObject =
        null;
    }

    setJoined(false);
    setParticipants(0);
    setStatus("idle");
  };

  if (!joined) {

    return (

      <div className="room">

        <h1>Video Chat</h1>

        <Button
          type="primary"
          onClick={createRoom}
        >
          Create Meeting
        </Button>

        <input
          placeholder="Enter Room ID"
          value={roomId}
          onChange={(e) =>
            setRoomId(e.target.value)
          }
        />

        <Button
          type="primary"
          onClick={joinRoom}
        >
          Join Meeting
        </Button>

      </div>
    );
  }

  return (

    <div className="App-header">

      <h2>
        Room: {roomId}
      </h2>

      <h3>
        Status: {status}
      </h3>

      <h3>
        Participants: {participants}
      </h3>

      <div className="video-container">

        <video
          ref={localVideo}
          autoPlay
          muted
          playsInline
        />

        <video
          ref={remoteVideo}
          autoPlay
          playsInline
        />

      </div>

      <div className="controls">

        {participants === 1 && (

          <Button
            type="primary"
            onClick={startMeeting}
          >
            Start Meeting
          </Button>
        )}

        <Button onClick={toggleMute}>
          {muted ? "Unmute" : "Mute"}
        </Button>

        <Button onClick={toggleVideo}>
          {videoOff
            ? "Enable Video"
            : "Disable Video"}
        </Button>

        <Button
          danger
          onClick={leaveMeeting}
        >
          Leave Meeting
        </Button>

      </div>

    </div>
  );
}

export default App;